import urllib.parse
import ipaddress
import socket
from typing import Optional, Set
import re

class URLValidator:
    BLOCKED_SCHEMES = {'file', 'ftp', 'gopher', 'data', 'javascript'}
    ALLOWED_SCHEMES = {'http', 'https'}
    BLOCKED_PORTS = {22, 23, 25, 3306, 5432, 6379, 27017}
    PRIVATE_IP_RANGES = [
        ipaddress.ip_network('10.0.0.0/8'),
        ipaddress.ip_network('172.16.0.0/12'),
        ipaddress.ip_network('192.168.0.0/16'),
        ipaddress.ip_network('127.0.0.0/8'),
        ipaddress.ip_network('169.254.0.0/16'),
        ipaddress.ip_network('::1/128'),
        ipaddress.ip_network('fc00::/7'),
        ipaddress.ip_network('fe80::/10'),
    ]
    METADATA_ENDPOINTS = [
        '169.254.169.254',
        'metadata.google.internal',
        'fd00:ec2::254'
    ]
    
    @classmethod
    def validate_url(cls, url: str) -> tuple[bool, Optional[str]]:
        if not url or not isinstance(url, str):
            return False, "Invalid URL format"
        
        if len(url) > 2048:
            return False, "URL exceeds maximum length"
        
        try:
            parsed = urllib.parse.urlparse(url)
        except Exception:
            return False, "Failed to parse URL"
        
        if parsed.scheme not in cls.ALLOWED_SCHEMES:
            return False, f"Scheme '{parsed.scheme}' not allowed"
        
        if not parsed.netloc:
            return False, "Missing hostname"
        
        hostname = parsed.hostname
        if not hostname:
            return False, "Invalid hostname"
        
        if hostname.lower() in cls.METADATA_ENDPOINTS:
            return False, "Access to metadata endpoints is blocked"
        
        if cls._is_ip_address(hostname):
            if not cls._validate_ip_address(hostname):
                return False, "Access to private IP addresses is blocked"
        else:
            if not cls._validate_hostname(hostname):
                return False, "Invalid or blocked hostname"
        
        port = parsed.port
        if port and port in cls.BLOCKED_PORTS:
            return False, f"Port {port} is blocked"
        
        return True, None
    
    @classmethod
    def _is_ip_address(cls, hostname: str) -> bool:
        try:
            ipaddress.ip_address(hostname)
            return True
        except ValueError:
            return False
    
    @classmethod
    def _validate_ip_address(cls, ip_str: str) -> bool:
        try:
            ip = ipaddress.ip_address(ip_str)
            
            for private_range in cls.PRIVATE_IP_RANGES:
                if ip in private_range:
                    return False
            
            if ip.is_multicast or ip.is_reserved or ip.is_loopback:
                return False
            
            return True
        except ValueError:
            return False
    
    @classmethod
    def _validate_hostname(cls, hostname: str) -> bool:
        if len(hostname) > 253:
            return False
        
        if hostname.startswith('.') or hostname.endswith('.'):
            return False
        
        pattern = re.compile(
            r'^(?!-)[A-Za-z0-9-]{1,63}(?<!-)(\.[A-Za-z0-9-]{1,63})*$'
        )
        if not pattern.match(hostname):
            return False
        
        try:
            ip_addresses = socket.getaddrinfo(hostname, None)
            for addr_info in ip_addresses:
                ip_str = addr_info[4][0]
                if not cls._validate_ip_address(ip_str):
                    return False
        except socket.gaierror:
            return False
        except Exception:
            return False
        
        return True


def fetch_webhook_content(url: str, timeout: int = 10, max_size: int = 10485760) -> dict:
    import requests
    from requests.adapters import HTTPAdapter
    from urllib3.util.retry import Retry
    
    is_valid, error_message = URLValidator.validate_url(url)
    if not is_valid:
        return {
            'success': False,
            'error': f'URL validation failed: {error_message}',
            'content': None
        }
    
    session = requests.Session()
    
    retry_strategy = Retry(
        total=3,
        backoff_factor=1,
        status_forcelist=[429, 500, 502, 503, 504],
        allowed_methods=["GET", "POST"]
    )
    adapter = HTTPAdapter(max_retries=retry_strategy)
    session.mount("http://", adapter)
    session.mount("https://", adapter)
    
    headers = {
        'User-Agent': 'WebhookProcessor/1.0',
        'Accept': 'application/json, text/plain, */*',
        'Accept-Encoding': 'gzip, deflate',
    }
    
    try:
        response = session.get(
            url,
            timeout=timeout,
            headers=headers,
            allow_redirects=True,
            stream=True,
            verify=True
        )
        
        if response.status_code != 200:
            return {
                'success': False,
                'error': f'HTTP {response.status_code}: {response.reason}',
                'content': None,
                'status_code': response.status_code
            }
        
        content_length = response.headers.get('Content-Length')
        if content_length and int(content_length) > max_size:
            return {
                'success': False,
                'error': f'Content size exceeds maximum allowed size of {max_size} bytes',
                'content': None
            }
        
        content = b''
        for chunk in response.iter_content(chunk_size=8192):
            content += chunk
            if len(content) > max_size:
                return {
                    'success': False,
                    'error': f'Content size exceeds maximum allowed size of {max_size} bytes',
                    'content': None
                }
        
        content_type = response.headers.get('Content-Type', '')
        
        try:
            decoded_content = content.decode('utf-8')
        except UnicodeDecodeError:
            decoded_content = content.decode('latin-1')
        
        return {
            'success': True,
            'error': None,
            'content': decoded_content,
            'status_code': response.status_code,
            'content_type': content_type,
            'headers': dict(response.headers)
        }
        
    except requests.exceptions.Timeout:
        return {
            'success': False,
            'error': f'Request timed out after {timeout} seconds',
            'content': None
        }
    except requests.exceptions.SSLError as e:
        return {
            'success': False,
            'error': f'SSL verification failed: {str(e)}',
            'content': None
        }
    except requests.exceptions.ConnectionError as e:
        return {
            'success': False,
            'error': f'Connection error: {str(e)}',
            'content': None
        }
    except requests.exceptions.RequestException as e:
        return {
            'success': False,
            'error': f'Request failed: {str(e)}',
            'content': None
        }
    except Exception as e:
        return {
            'success': False,
            'error': f'Unexpected error: {str(e)}',
            'content': None
        }
    finally:
        session.close()


def display_webhook_content(url: str) -> None:
    result = fetch_webhook_content(url)
    
    if result['success']:
        print(f"Successfully fetched content from: {url}")
        print(f"Status Code: {result['status_code']}")
        print(f"Content Type: {result['content_type']}")
        print("\nContent:")
        print("-" * 80)
        print(result['content'])
        print("-" * 80)
    else:
        print(f"Failed to fetch content from: {url}")
        print(f"Error: {result['error']}")